import React from 'react';
import { AsyncStorage } from 'react-native';

class LocalDataManager extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      userTokens: {},
      profileInformation: {},
      appSettings: {}
    };
  }

  async componentDidMount() {
    const userTokens = await AsyncStorage.getItem('userTokens');
    const profileInformation = await AsyncStorage.getItem('profileInformation');
    const appSettings = await AsyncStorage.getItem('appSettings');
    this.setState({ userTokens, profileInformation, appSettings });
  }

  async saveUserToken(token) {
    await AsyncStorage.setItem('userTokens', token);
  }

  async saveProfileInformation(information) {
    await AsyncStorage.setItem('profileInformation', information);
  }

  async saveAppSettings(settings) {
    await AsyncStorage.setItem('appSettings', settings);
  }

  render() {
    return (
      <View>
        <Text>{this.state.userTokens}</Text>
        <Text>{this.state.profileInformation}</Text>
        <Text>{this.state.appSettings}</Text>
      </View>
    );
  }
}